import type { InputHTMLAttributes, RefObject } from 'react';

import type { TestComponentProps } from '../../types/test-component';
import type { IconSize } from '../Icon/Icon.types';
import type { IconButtonProps } from '../IconButton';
import type { Option } from '../Select/Select.types';

export type SearchSizeVariantsType = 'small' | 'medium';

interface SearchParent extends Omit<InputHTMLAttributes<HTMLInputElement>, 'size' | 'type'> {}

export interface SearchProps extends SearchParent, TestComponentProps {
	/**
	 * Размеры.
	 */
	size?: SearchSizeVariantsType;
	/**
	 * Растягивает поле на всю ширину родителя.
	 */
	fullWidth?: boolean;
	/**
	 * Название класса для текстового поля.
	 */
	inputClassName?: string;
	/**
	 * Обработчик очистки текстового поля.
	 */
	onClear?: () => void;
	/**
	 * Обработчик поиска. Так же вызывается при нажатии на Enter.
	 */
	onSearch?: (value?: SearchProps['value']) => string | void;
	/**
	 *  Категории по которым можно применить фильтр
	 */
	filterItems?: Array<Option<string>>;
	/**
	 * Выбранная категория фильтра
	 */
	selectedFilter?: Option<string> | null;
	/**
	 * Обратный вызов функции срабатывает при выборе фильтра.
	 */
	onFilterChange?: (filterItem: Option<string> | null) => void;
	/**
	 * Включает адаптив и изменяет
	 */
	isAdaptive?: boolean;
	/**
	 * Конфиг для маски
	 */
	maskConfig?: any;
}

export const iconSize: Record<SearchSizeVariantsType, IconSize> = {
	small: 'medium',
	medium: 'large',
};

interface SearchDropdown<T> extends TestComponentProps {
	/**
	 * Enabling multiple selections.
	 * @default false
	 */
	multiple?: boolean;
	/**
	 * Callback fired when a menu item is selected.
	 *
	 * @param {Array<SelectItem>} values The array of selected values.
	 */
	onChange: (values: Array<Option<T>>) => void;
	/**
	 * Menu available options.
	 */
	options: Array<Option<T>>;
	/**
	 * Selected options.
	 */
	values: Array<Option<T>>;
	onOutsideClick?: () => void;
	/**
	 * Making views of option elements
	 */
	makeOption: (option: Option<T>, selected: boolean) => React.JSX.Element;
	loading?: boolean;
	loadingText?: string | React.ReactNode;
	/**
	 *  The ID of the element where the dropdown menu will be mounted.
	 */
	applicationRootElementID?: string;
	/**
	 * The ID with which to be created the dropdown menu.
	 */
	dropdownElementID?: string;
}

export interface SearchDropdownProps<T1, T2 = HTMLElement> extends SearchDropdown<T1> {
	/**
	 * Reference on component relative to which the dropdown is positioned
	 */
	parentRef: React.RefObject<T2>;
	/**
	 * Флаг отвечающий за скрытие/пока dropDownMenu
	 * */
	isOpen?: boolean;
	/**
	 * Устанавливает состояние за скрытие/пока dropDownMenu
	 * */
	handleSetOpen?: (arg: boolean) => void;
}

export interface ControlledSearch extends SearchParent, TestComponentProps {
	type: 'search';
}
export interface ControlledSearchProps extends ControlledSearch {
	inputRef: RefObject<HTMLInputElement>;
	dataTestIconId: string;
	iconButton: IconButtonProps;
	/**
	 * Конфиг для маски
	 */
	maskConfig?: any;
}
